    const s = new URLSearchParams();
    s.set("offset", String(r.offset));
    s.set("limit", String(r.limit));
    if (r.sortKeys && r.sortKeys.length > 0) {
      s.set("sortKeys", JSON.stringify(r.sortKeys));
    } else {
      if (r.orderBy) s.set("orderBy", r.orderBy);
      if (r.orderDir) s.set("orderDir", r.orderDir);
    }
    if (r.filter) {
      s.set("filter", r.filter);
    }
    if (r.filters != null) {
      const i = Array.isArray(r.filters) ? r.filters.map(serializeFilterClause) : Array.isArray(r.filters.clauses) ? r.filters.clauses.map(serializeFilterClause) : [];
      const a = JSON.stringify(i);
      s.set("filters", a);
      s.set("structuredFilters", a);
    }
    return fetchJson(`/api/data/${e}/${encodeURIComponent(t)}/${encodeURIComponent(n)}?${s.toString()}`);
